+  Server = 'SERVER',
+  InvalidImage = 'INVALID_IMAGE',
+  Timeout = 'TIMEOUT',
+  InvalidConfig = 'INVALID_CONFIG',
+  Unauthorized = 'UNAUTHORIZED',
+  RateLimited = 'RATE_LIMITED',
+}
